const fail = (message) => [{
  json: {
    success: false,
    error: message,
  },
}];

const body = $input.first().json.body;

if (!body || typeof body !== 'object') {
  return fail('Invalid request body');
}

const required = [
  'lesson_id',
  'submission_id',
  'student_id',
  'metadata',
  'lesson_plan',
  'homework_task',
  'homework_answer',
];

const missing = required.filter((field) => {
  const value = body[field];
  if (value === null || value === undefined) return true;
  if (typeof value === 'string' && value.trim() === '') return true;
  return false;
});

if (missing.length > 0) {
  return fail('Missing fields: ' + missing.join(', '));
}

if (!body.metadata || typeof body.metadata !== 'object') {
  return fail('Invalid metadata');
}

if (!body.lesson_plan || typeof body.lesson_plan !== 'object') {
  return fail('Invalid lesson_plan');
}

if (!body.homework_task || typeof body.homework_task !== 'string') {
  return fail('Invalid homework_task');
}

if (!body.homework_answer || typeof body.homework_answer !== 'string') {
  return fail('Invalid homework_answer');
}

return [{
  json: {
    success: true,
    lesson_id: String(body.lesson_id),
    submission_id: String(body.submission_id),
    student_id: String(body.student_id),
    metadata: body.metadata,
    lesson_plan: body.lesson_plan,
    homework_task: String(body.homework_task).substring(0, 3000),
    homework_answer: String(body.homework_answer).substring(0, 5000),
  },
}];

const fail = (message) => [{
  json: {
    success: false,
    error: message,
  },
}];

const input = $input.first().json;

const raw =
  input?.choices?.[0]?.message?.content ||
  input?.body?.choices?.[0]?.message?.content ||
  input?.data?.choices?.[0]?.message?.content ||
  '';

if (!raw || typeof raw !== 'string') {
  return fail('Empty homework evaluation response from AI');
}

let parsed;

try {
  parsed = JSON.parse(raw);
} catch (error) {
  return fail('AI returned invalid homework evaluation JSON');
}

if (!parsed || typeof parsed !== 'object') {
  return fail('AI homework evaluation response is not an object');
}

const allowedLevels = ['Excellent', 'Good', 'Developing', 'Needs Support'];

const understandingLevel = String(parsed.understanding_level || '').trim();
if (!allowedLevels.includes(understandingLevel)) {
  return fail('AI homework evaluation response has invalid understanding_level');
}

const understandingScore = Number(parsed.understanding_score);
if (
  !Number.isFinite(understandingScore) ||
  understandingScore < 1 ||
  understandingScore > 5
) {
  return fail('AI homework evaluation response has invalid understanding_score');
}

const strengths = Array.isArray(parsed.strengths)
  ? parsed.strengths.map(item => String(item)).filter(Boolean).slice(0, 3)
  : [];

const improvements = Array.isArray(parsed.improvements)
  ? parsed.improvements.map(item => String(item)).filter(Boolean).slice(0, 3)
  : [];

if (strengths.length === 0) {
  return fail('AI homework evaluation response missing strengths');
}

if (improvements.length === 0) {
  return fail('AI homework evaluation response missing improvements');
}

return [
  {
    json: {
      success: true,
      submission_id: $('Build Homework Evaluation Prompt').first().json.submission_id || '',
      understanding_level: understandingLevel,
      understanding_score: Math.round(understandingScore),
      feedback: String(parsed.feedback || '').substring(0, 2000),
      strengths,
      improvements,
      teacher_note: String(parsed.teacher_note || '').substring(0, 1000),
    },
  },
];

